const seen = new Set<string>();
export const n4KanjiCandidateData: N4KanjiCandidateEntry[] = raw
  .filter((entry) => {
    if (seen.has(entry.kanji)) return false;
    seen.add(entry.kanji);
    return true;
  })
  .map((entry, index) => ({
    id: `n4-kanji-${String(index + 1).padStart(4, '0')}`,
    kanji: entry.kanji,
    onyomi: entry.onyomi,
    kunyomi: entry.kunyomi,
    meanings: entry.meanings,
    jlptLevel: 'N4' as const,
    reviewStatus: REVIEW,
  }));
